import{_ as o,o as i,c as d,ag as l}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Про Dotfiles | Dotfiles (UK)","titleTemplate":":title","description":"Дослідіть технічний огляд Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Про Dotfiles | Dotfiles","description":"Дослідіть технічний огляд Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Про Dotfiles | Dotfiles preview","canonical":"/uk/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Про Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/uk/about/"},"headers":[],"relativePath":"uk/about/index.md","filePath":"uk/about/index.md","lastUpdated":1773010926000}'),a={name:"uk/about/index.md"};function t(c,e,s,r,h,n){return i(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="про-dotfiles" tabindex="-1">Про Dotfiles <a class="header-anchor" href="#про-dotfiles" aria-label="Permalink to &quot;Про Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 — кросплатформна конфігурація оболонки, керована Chezmoi.</p><h2 id="встановлення" tabindex="-1">Встановлення <a class="header-anchor" href="#встановлення" aria-label="Permalink to &quot;Встановлення&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="перевірка" tabindex="-1">Перевірка <a class="header-anchor" href="#перевірка" aria-label="Permalink to &quot;Перевірка&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="основні-команди" tabindex="-1">Основні команди <a class="header-anchor" href="#основні-команди" aria-label="Permalink to &quot;Основні команди&quot;">​</a></h2><ul><li><code>dot apply</code> застосовує зміни конфігурації.</li><li><code>dot update</code> оновлює репозиторій та прогріває кеші.</li><li><code>dot doctor</code> перевіряє шляхи, інструменти та стан оболонки.</li><li><code>dot heal</code> відновлює відсутній або пошкоджений стан.</li><li><code>dot smoke-test</code> перевіряє основні ланцюжки інструментів.</li></ul><h2 id="пов-язане" tabindex="-1">Пов&#39;язане <a class="header-anchor" href="#пов-язане" aria-label="Permalink to &quot;Пов&#39;язане&quot;">​</a></h2><ul><li><a href="/uk/aliases/">Аліаси</a></li><li><a href="/uk/functions/">Функції</a></li><li><a href="/uk/paths/">Шляхи</a></li></ul><h2 id="основні-команди-1" tabindex="-1">Основні команди <a class="header-anchor" href="#основні-команди-1" aria-label="Permalink to &quot;Основні команди&quot;">​</a></h2><p>CLI <code>dot</code> надає 53 команди, організовані за категоріями.</p><h3 id="ядро" tabindex="-1">Ядро <a class="header-anchor" href="#ядро" aria-label="Permalink to &quot;Ядро&quot;">​</a></h3><ul><li><code>dot apply</code> — застосовує зміни конфігурації.</li><li><code>dot sync</code> — отримує найновіший стан репозиторію та застосовує.</li><li><code>dot update</code> — оновлює репозиторій і прогріває кеші.</li><li><code>dot add</code> — додає нові файли до джерела Chezmoi.</li><li><code>dot diff</code> — показує очікувані зміни перед застосуванням.</li><li><code>dot status</code> — відображає статус керованих файлів.</li><li><code>dot remove</code> — знімає файл з управління та видаляє запис джерела.</li><li><code>dot cd</code> — відкриває оболонку в каталозі джерела Chezmoi.</li><li><code>dot edit</code> — відкриває керований файл у вашому редакторі.</li><li><code>dot clean-cache</code> — очищує тимчасові кеші.</li><li><code>dot prewarm</code> — попередньо заповнює кеші для швидшого запуску оболонки.</li></ul><h3 id="діагностика" tabindex="-1">Діагностика <a class="header-anchor" href="#діагностика" aria-label="Permalink to &quot;Діагностика&quot;">​</a></h3><ul><li><code>dot doctor</code> — перевіряє шляхи, інструменти та стан оболонки.</li><li><code>dot heal</code> — автоматично виправляє відсутній або пошкоджений стан.</li><li><code>dot health</code> — запускає легку перевірку працездатності.</li><li><code>dot verify</code> — перевіряє цілісність файлів відносно джерела.</li><li><code>dot scorecard</code> — виводить оцінку якості конфігурації.</li><li><code>dot snapshot</code> — фіксує поточний стан для подальшого порівняння.</li><li><code>dot smoke-test</code> — повністю перевіряє основні ланцюги інструментів.</li><li><code>dot chaos</code> — впроваджує збої для тестування самовідновлення.</li><li><code>dot bundle</code> — експортує портативний пакет конфігурації.</li><li><code>dot rollback</code> — відкочує до попереднього знімка.</li><li><code>dot drift</code> — виявляє несанкціоновані зміни в керованих файлах.</li><li><code>dot history</code> — показує журнал історії apply/sync.</li><li><code>dot benchmark</code> — вимірює час запуску оболонки.</li><li><code>dot perf</code> — профілює повільну ініціалізацію оболонки.</li></ul><h3 id="зовнішніи-вигляд" tabindex="-1">Зовнішній вигляд <a class="header-anchor" href="#зовнішніи-вигляд" aria-label="Permalink to &quot;Зовнішній вигляд&quot;">​</a></h3><ul><li><code>dot theme</code> — перемикає колірну схему терміналу.</li><li><code>dot wallpaper</code> — встановлює шпалери робочого столу (macOS).</li><li><code>dot fonts</code> — встановлює або оновлює Nerd Fonts.</li><li><code>dot tune</code> — налаштовує щільність інтерфейсу та стиль запрошення.</li></ul><h3 id="безпека" tabindex="-1">Безпека <a class="header-anchor" href="#безпека" aria-label="Permalink to &quot;Безпека&quot;">​</a></h3><ul><li><code>dot backup</code> — створює зашифровані резервні копії конфігурації.</li><li><code>dot encrypt-check</code> — перевіряє шифрування секретів у стані спокою.</li><li><code>dot firewall</code> — налаштовує правила брандмауера хоста.</li><li><code>dot telemetry</code> — керує анонімною телеметрією використання.</li><li><code>dot dns-doh</code> — вмикає DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — негайно блокує екран.</li><li><code>dot usb-safety</code> — обмежує автоматичне монтування USB-накопичувачів.</li></ul><h3 id="секрети" tabindex="-1">Секрети <a class="header-anchor" href="#секрети" aria-label="Permalink to &quot;Секрети&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — ініціалізує бекенд секретів (age / GPG).</li><li><code>dot secrets</code> — показує зашифровані записи секретів.</li><li><code>dot secrets-create</code> — створює новий зашифрований секрет.</li><li><code>dot ssh-key</code> — генерує або ротує пари SSH-ключів.</li><li><code>dot ssh-cert</code> — запитує SSH-сертифікат у центру сертифікації.</li></ul><h3 id="ші" tabindex="-1">ШІ <a class="header-anchor" href="#ші" aria-label="Permalink to &quot;ШІ&quot;">​</a></h3><ul><li><code>dot ai</code> — відкриває інтерактивну сесію помічника ШІ.</li><li><code>dot ai-setup</code> — налаштовує API-ключі для провайдерів ШІ.</li><li><code>dot ai-query</code> — надсилає одноразовий запит до моделі ШІ.</li><li>Обгортки інструментів ШІ: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="інструменти" tabindex="-1">Інструменти <a class="header-anchor" href="#інструменти" aria-label="Permalink to &quot;Інструменти&quot;">​</a></h3><ul><li><code>dot tools</code> — показує вбудовані CLI-заміни та їх статус.</li><li><code>dot new</code> — створює новий файл псевдоніма або функції.</li><li><code>dot sandbox</code> — відкриває одноразову пісочницю.</li><li><code>dot keys</code> — показує поточні прив&#39;язки клавіш.</li><li><code>dot learn</code> — запускає інтерактивний підручник.</li></ul><h3 id="мета" tabindex="-1">Мета <a class="header-anchor" href="#мета" aria-label="Permalink to &quot;Мета&quot;">​</a></h3><ul><li><code>dot upgrade</code> — оновлює Dotfiles до останнього випуску.</li><li><code>dot packages</code> — показує встановлені пакети, керовані Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — виводить інформацію про версію або використання</li></ul>',28)])])}const k=o(a,[["render",t]]);export{p as __pageData,k as default};
